%[text] # 例4.10（画像のDFT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_10"; % mfilename

imgname = "msipimg07";
imgfmt = "tiff";

minmaxnorm = @(x) (x-min(x(:)))/(max(x(:))-min(x(:)));
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## 原画像の表示
figure(1) %[output:4250e88f]
imshow(X) %[output:4250e88f]
title('原画像')  %[output:4250e88f]
%%
%[text] ## 画像のDFT
Y = fft2(X,96,96);
%%
%[text] ## 振幅スペクトル
figure(2) %[output:73b7a914]

Ymag = abs(Y);
Ymagdb = 10*log10(Ymag);
Ymagimg = minmaxnorm(fftshift(Ymagdb));
imshow(Ymagimg) %[output:73b7a914]

title('振幅スペクトル（強調）')  %[output:73b7a914]
%%
%[text] ## 位相スペクトル
figure(3) %[output:4e56cf66]

Yang = angle(Y);
Yangimg = fftshift(Yang)/pi+0.5;
imshow(Yangimg) %[output:4e56cf66]

title('位相スペクトル（正規化）')  %[output:4e56cf66]
%%
%[text] ## 振幅からの再構成
figure(4) %[output:7a17df8f]

Xmag = ifft2(Ymag);
imshow(Xmag) %[output:7a17df8f]

title('振幅からの再構成')  %[output:7a17df8f]
%%
%[text] ## 位相からの再構成
figure(5)

Xang = real(ifft2(exp(1j*Yang)));
Xangimg = minmaxnorm(Xang);
imshow(Xangimg)

title('位相からの再構成（正規化）') 
%%
%[text] ## 結果出力
imwrite(X,fullfile(resfolder,"fig04-04a.png"))
imwrite(Ymagimg,fullfile(resfolder,"fig04-04b.png"))
imwrite(Yangimg,fullfile(resfolder,"fig04-04c.png"))
imwrite(Xmag,fullfile(resfolder,"fig04-04d.png"))
imwrite(Xangimg,fullfile(resfolder,"fig04-04e.png"))
